previewCss:
.darma-loader-darma-custom-093 {
  width: 40px;
  aspect-ratio: 1;
  display: grid;
}
.darma-loader-darma-custom-093::before,
.darma-loader-darma-custom-093::after {
  content: "";
  grid-area: 1/1;
  background: var(--loader-color, #ffa500);
  clip-path: polygon(0 0,101% 0, 0 100%);
  animation: darma-loader-darma-custom-093-l13 2s infinite;
}
.darma-loader-darma-custom-093::after {
  --s:-1,-1;
}
@keyframes darma-loader-darma-custom-093-l13 {
    0%,
    10%  {transform:scale(var(--s,1)) translate(0,0)        rotate(0deg)}
    33%  {transform:scale(var(--s,1)) translate(20px,-20px) rotate(0deg)}
    66%  {transform:scale(var(--s,1)) translate(20px,-20px) rotate(180deg)}
    90%,
    100% {transform:scale(var(--s,1)) translate(0px,0px)    rotate(180deg)}
}

